onClick:
{{
  (async () => {
    // 1. LẤY DỮ LIỆU TỪ CÁC WIDGET
    const ma_vl = inp_BP_Ma.text.trim();            
    const so_luong_xuat = Number(inp_BP_SoLuong.text);     
    const nguoi_xuat = inp_BP_NguoiDat.text 
    const trang_thai = sel_BP_TrangThai.selectedOptionValue; 
    const ghi_chu = inp_BP_GhiChu.text;                    

    if (!ma_vl || so_luong_xuat <= 0) {
        return showAlert("❌ Vui lòng nhập mã và số lượng xuất hợp lệ!", "warning");
    }
    if (!trang_thai) {
        return showAlert("❌ Vui lòng chọn Trạng thái xuất!", "warning");
    }

    try {
        showAlert("⏳ Đang rà soát và tính toán số lượng kho...", "info");

        // 2. RÀ SOÁT TỔNG SỐ LƯỢNG
        const rows = await Check_So_Luong_Phe.run({ code: ma_vl });
        let tong_ton_kho = 0;
        rows.forEach(r => tong_ton_kho += r.quantity);

        if (so_luong_xuat > tong_ton_kho) {
            return showAlert(`❌ Lỗi: Mã [${ma_vl}] chỉ còn tổng ${tong_ton_kho} cái.`, 'error');
        }

        // 3. THUẬT TOÁN TRỪ LÙI DẦN (FIFO)
        let so_luong_con_lai_can_xuat = so_luong_xuat;

        for (let i = 0; i < rows.length; i++) {
            if (so_luong_con_lai_can_xuat <= 0) break; 

            let dong_hien_tai = rows[i];
            let so_luong_se_tru = 0;
            let trang_thai_moi = 'Pending';

            if (dong_hien_tai.quantity <= so_luong_con_lai_can_xuat) {
                so_luong_se_tru = dong_hien_tai.quantity;
                trang_thai_moi = 'DA_XUAT'; 
                so_luong_con_lai_can_xuat -= dong_hien_tai.quantity;
            } else {
                so_luong_se_tru = so_luong_con_lai_can_xuat;
                trang_thai_moi = 'Pending'; 
                so_luong_con_lai_can_xuat = 0; 
            }

            await Update_Dong_Phe.run({
                id: dong_hien_tai.id,
                deductQty: so_luong_se_tru,
                newStatus: trang_thai_moi
            });
        }

        // 4. GHI LỊCH SỬ XUẤT (CHỈ CÓ 1 LẦN DUY NHẤT Ở ĐÂY)
        await Insert_Lich_Su_Xuat.run({
            code: ma_vl,
            qty: so_luong_xuat,
            emp: nguoi_xuat,
            trang_thai: trang_thai,
            ghi_chu: ghi_chu
        });

        // 5. CẬP NHẬT GIAO DIỆN
        await Get_Scrap_List.run(); 
        await Get_LS_Phe.run();      
        resetWidget('Form1', true);  

        showAlert(`✅ Xuất thành công!`, "success");

    } catch (err) {
        showAlert("❌ Lỗi hệ thống: " + err.message, "error");
    }
  })()
}}
